/* Test driver */
public class Main {
    public static void main(String[] args) {
        int[][] xMoves = {{1,1}, {0,0}};
        int[][] oMoves = {{0,1}};
        Game g = new Game(3, new HumanPlayer("X", Symbol.X, xMoves), new HumanPlayer("O", Symbol.O, oMoves));
        g.playTurn();
        if (g.getBoard().getSymbolAt(1,1) != Symbol.X) { System.out.println("FAIL_PLACE"); return; }
        boolean undone = g.undoLastMove();
        if (undone && g.getBoard().getSymbolAt(1,1) == null) System.out.println("OK_UNDO");
        else System.out.println("FAIL_UNDO");
    }
}
